using Microsoft.AspNetCore.Components;
using sv_3580c1dfd6314b1a9079af7dc589bd19.Models;
using sv_3580c1dfd6314b1a9079af7dc589bd19.Services;

namespace sv_3580c1dfd6314b1a9079af7dc589bd19.Components.Pages.Apply;

/// <summary>
/// Base class for wizard step pages. Handles session ID retrieval across the
/// prerender-to-interactive boundary using PersistentComponentState, and loads
/// the shared WizardData from the singleton store.
/// </summary>
public abstract class WizardStepBase : ComponentBase, IDisposable
{
    [Inject] protected WizardStateStore Store { get; set; } = default!;
    [Inject] protected IHttpContextAccessor HttpContextAccessor { get; set; } = default!;
    [Inject] protected PersistentComponentState PersistentState { get; set; } = default!;
    [Inject] protected NavigationManager Nav { get; set; } = default!;

    protected WizardData Data { get; private set; } = new();

    private PersistingComponentStateSubscription _subscription;

    protected override void OnInitialized()
    {
        _subscription = PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("wizardSessionId", SessionId);
            return Task.CompletedTask;
        });

        string sessionId;
        if (PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored))
        {
            sessionId = restored ?? "";
        }
        else
        {
            // During prerender, HttpContext is available
            sessionId = HttpContextAccessor.HttpContext?.Items["WizardSessionId"] as string ?? "";
        }

        SessionId = sessionId;

        if (!string.IsNullOrEmpty(sessionId))
        {
            Data = Store.GetOrCreate(sessionId);
        }
    }

    protected string SessionId { get; private set; } = "";

    /// <summary>
    /// Marks the given step number as completed and navigates to the next URL.
    /// Data is already persisted in the store (same object reference).
    /// </summary>
    protected void SaveAndNavigate(int completedStep, string nextUrl)
    {
        Data.CompletedSteps.Add(completedStep);
        Nav.NavigateTo(nextUrl);
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

