@page "/apply/personal-info"
@rendermode InteractiveServer
@inherits WizardStepBase

<PageTitle>Personal Info - Job Application</PageTitle>

<h3>Personal Information</h3>
<p class="text-muted">Tell us about yourself.</p>

<div class="mb-3" style="max-width: 400px;">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="Data.PersonalInfo.Name" placeholder="Jane Doe" />
</div>

<div class="mb-3" style="max-width: 400px;">
    <label class="form-label">Email Address</label>
    <input class="form-control" type="email" @bind="Data.PersonalInfo.Email" placeholder="jane@example.com" />
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private void Next() => SaveAndNavigate(1, "/apply/experience");
}

@page "/apply/review"
@rendermode InteractiveServer
@inherits WizardStepBase

<PageTitle>Review - Job Application</PageTitle>

<h3>Review Your Application</h3>
<p class="text-muted">Please confirm all details before submitting.</p>

<div class="card mb-4">
    <div class="card-header"><strong>Personal Information</strong></div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Name</dt>
            <dd class="col-sm-9">@NoneIfEmpty(Data.PersonalInfo.Name)</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@NoneIfEmpty(Data.PersonalInfo.Email)</dd>
        </dl>
    </div>
</div>

<div class="card mb-4">
    <div class="card-header"><strong>Work Experience</strong></div>
    <div class="card-body">
        @if (Data.Experience.Count == 0)
        {
            <p class="text-muted mb-0">No experience entries added.</p>
        }
        else
        {
            <table class="table table-sm mb-0">
                <thead>
                    <tr><th>Company</th><th>Title</th><th>Years</th></tr>
                </thead>
                <tbody>
                    @foreach (var e in Data.Experience)
                    {
                        <tr><td>@e.Company</td><td>@e.Title</td><td>@e.Years</td></tr>
                    }
                </tbody>
            </table>
        }
    </div>
</div>

<div class="card mb-4">
    <div class="card-header"><strong>References</strong></div>
    <div class="card-body">
        @if (Data.References.Count == 0)
        {
            <p class="text-muted mb-0">No references added.</p>
        }
        else
        {
            <table class="table table-sm mb-0">
                <thead>
                    <tr><th>Name</th><th>Email</th><th>Relationship</th></tr>
                </thead>
                <tbody>
                    @foreach (var r in Data.References)
                    {
                        <tr><td>@r.Name</td><td>@r.Email</td><td>@r.Relationship</td></tr>
                    }
                </tbody>
            </table>
        }
    </div>
</div>

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-secondary" @onclick='() => Nav.NavigateTo("/apply/references")'>← Back</button>
    <button class="btn btn-success" @onclick="Submit" disabled="@_submitted">
        @(_submitted ? "Submitted ✓" : "Submit Application")
    </button>
</div>

@if (_submitted)
{
    <div class="alert alert-success mt-3">
        Your application has been submitted successfully!
    </div>
}

@code {
    private bool _submitted;

    private void Submit()
    {
        Data.CompletedSteps.Add(4);
        _submitted = true;
    }

    private static string NoneIfEmpty(string? value) =>
        string.IsNullOrWhiteSpace(value) ? "—" : value;
}

