    {
        ("apply/personal-info", "Personal Info"),
        ("apply/experience", "Experience"),
        ("apply/references", "References"),
        ("apply/review", "Review")
    };

    var currentStep = -1;
    HashSet<int>? completedSteps = null;

    if (isWizardPage)
    {
        for (int i = 0; i < wizardSteps.Length; i++)
        {
            if (uri == wizardSteps[i].Path)
            {
                currentStep = i;
                break;
            }
        }

        var sessionId = HttpContextAccessor.HttpContext?.Items["WizardSessionId"] as string;
        if (!string.IsNullOrEmpty(sessionId))
        {
            completedSteps = WizardStore.GetOrCreate(sessionId).CompletedSteps;
        }
    }
}

