                <div class="wizard-steps">
                    @for (int i = 0; i < wizardSteps.Length; i++)
                    {
                        var step = wizardSteps[i];
                        var isCurrent = i == currentStep;
                        var isCompleted = completedSteps?.Contains(i + 1) == true;
                        var stepClass = isCurrent ? "active" : isCompleted ? "completed" : "";

                        <a href="@step.Path" class="wizard-step @stepClass">
                            <div class="step-circle">
                                @if (isCompleted && !isCurrent)
                                {
                                    <span>✓</span>
