arguments.new_str:
@inherits LayoutComponentBase
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor
@inject WizardStateStore WizardStore

@{
    var uri = Nav.ToBaseRelativePath(Nav.Uri).TrimEnd('/').ToLowerInvariant();
    var isWizardPage = uri.StartsWith("apply/");

    var wizardSteps = new (string Path, string Label)[]
    {
        ("apply/personal-info", "Personal Info"),
        ("apply/experience", "Experience"),
        ("apply/references", "References"),
        ("apply/review", "Review")
    };

    var currentStep = -1;
    HashSet<int>? completedSteps = null;

    if (isWizardPage)
    {
        for (int i = 0; i < wizardSteps.Length; i++)
        {
            if (uri == wizardSteps[i].Path)
            {
                currentStep = i;
                break;
            }
        }

        var sessionId = HttpContextAccessor.HttpContext?.Items["WizardSessionId"] as string;
        if (!string.IsNullOrEmpty(sessionId))
        {
            completedSteps = WizardStore.GetOrCreate(sessionId).CompletedSteps;
        }
    }
}

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        @if (isWizardPage)
        {
            <div class="wizard-progress px-4 py-3">
                <div class="step-counter">Step @(currentStep + 1) of @wizardSteps.Length</div>
                <div class="wizard-steps">
                    @for (int i = 0; i < wizardSteps.Length; i++)
                    {
                        var step = wizardSteps[i];
                        var isCurrent = i == currentStep;
                        var isCompleted = completedSteps?.Contains(i + 1) == true;
                        var stepClass = isCurrent ? "active" : isCompleted ? "completed" : "";

                        <a href="@step.Path" class="wizard-step @stepClass">
                            <div class="step-circle">
                                @if (isCompleted && !isCurrent)
                                {
                                    <span>✓</span>
                                }
                                else
                                {
                                    <span>@(i + 1)</span>
                                }
                            </div>
                            <span class="step-label">@step.Label</span>
                        </a>

                        @if (i < wizardSteps.Length - 1)
                        {
                            <div class="step-connector @(isCompleted ? "completed" : "")"></div>
                        }
                    }
                </div>
            </div>
        }
        else
        {
            <div class="top-row px-4">
                <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
            </div>
        }

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

